export interface CustomFontFace {
	base64: string;
	format: "opentype" | "woff2" | "truetype";
	style: "normal" | "italic";
}

export interface CustomFontEntry {
	id: "caroni" | "ibm-plex-sans-var" | "nunito"; // extend this union as more fonts are added
	cssFontFamily: string; // name registered in @font-face and used in font-family CSS
	label: string; // shown in the settings dropdown
	weightMin: number; // native weight range this font file actually supports
	weightMax: number; // equal to weightMin for a static/single-weight font
	faces: CustomFontFace[];
}

const CARONI_BASE64 =
	"";

const IBM_PLEX_SANS_VAR_ROMAN_BASE64 =
	"";

const IBM_PLEX_SANS_VAR_ITALIC_BASE64 =
	"";

const NUNITO_ROMAN_BASE64 =
	"";

const NUNITO_ITALIC_BASE64 =
	"";

export const CUSTOM_FONTS: CustomFontEntry[] = [
	{
		id: "caroni",
		cssFontFamily: "storyForge Caroni",
		label: "Caroni",
		weightMin: 400,
		weightMax: 400,
		faces: [{ base64: CARONI_BASE64, format: "opentype", style: "normal" }],
	},
	{
		id: "ibm-plex-sans-var",
		cssFontFamily: "storyForge IBM Plex Sans Var",
		label: "IBM Plex Sans",
		weightMin: 100,
		weightMax: 700,
		faces: [
			{ base64: IBM_PLEX_SANS_VAR_ROMAN_BASE64, format: "woff2", style: "normal" },
			{ base64: IBM_PLEX_SANS_VAR_ITALIC_BASE64, format: "woff2", style: "italic" },
		],
	},
	{
		id: "nunito",
		cssFontFamily: "storyForge Nunito",
		label: "Nunito",
		weightMin: 200,
		weightMax: 900,
		faces: [
			{ base64: NUNITO_ROMAN_BASE64, format: "truetype", style: "normal" },
			{ base64: NUNITO_ITALIC_BASE64, format: "truetype", style: "italic" },
		],
	},
];

/** One `@font-face` rule per face of every registered custom font, to be injected via `applyStyleToAllDocs`. */
export function buildCustomFontFaceCSS(): string {
	const rules: string[] = [];
	for (const font of CUSTOM_FONTS) {
		const weightDescriptor = font.weightMin === font.weightMax ? `${font.weightMin}` : `${font.weightMin} ${font.weightMax}`;
		for (const face of font.faces) {
			rules.push(
				`@font-face { font-family: "${font.cssFontFamily}"; src: url(data:font/${face.format};base64,${face.base64}) format("${face.format}"); font-weight: ${weightDescriptor}; font-style: ${face.style}; font-display: swap; }`,
			);
		}
	}
	return rules.join("\n");
}

/**
 * CSS for switching to a custom font at a given requested weight: real interpolation for a
 * variable font whose weightMin/weightMax range covers it (e.g. IBM Plex Sans Var); a no-op
 * weight declaration for a static/single-weight font (e.g. Caroni), since it has no "wght" axis.
 * Font-synthesis is deliberately left at its default (on) in both cases, so genuine <strong>/<b>
 * text typed in the editor still renders bold via the browser's synthetic bold, even though these
 * fonts have no real bold face — only the weight-picker-driven fake bolding is removed here.
 */
export function buildCustomFontFamilyDeclaration(font: CustomFontEntry, requestedWeight: number): string {
	if (font.weightMin === font.weightMax) {
		return `font-family: "${font.cssFontFamily}", var(--font-text);`;
	}
	// Explicit font-variation-settings, not just font-weight - relying solely on the browser's
	// implicit font-weight-range matching to drive a variable font's "wght" axis has proven
	// unreliable; being explicit here is what actually makes the weight change visible.
	const nativeWeight = Math.min(requestedWeight, font.weightMax);
	return `font-family: "${font.cssFontFamily}", var(--font-text); font-variation-settings: "wght" ${nativeWeight};`;
}
